   242→  cachedHeaderRefEmbedding = null;
   243→  cachedNoiseRefEmbedding = null;
   244→}
   245→
   246→export async function extractTitleWithEmbeddings(
   247→  text: string,
   248→  embed: EmbedFn
   249→): Promise<string | undefined> {
   250→  if (!text || text.trim().length === 0) {
   251→    return undefined;
   252→  }
   253→
   254→  const lines = text.split("\n");
   255→  const candidates = buildCandidates(lines);
   256→
   257→  if (candidates.length === 0) {
   258→    return undefined;
   259→  }
   260→
   261→  // Cache reference embeddings
   262→  if (!cachedTitleRefEmbedding) {
   263→    cachedTitleRefEmbedding = await embed(TITLE_REFERENCE);
   264→  }
   265→  if (!cachedHeaderRefEmbedding) {
   266→    cachedHeaderRefEmbedding = await embed(HEADER_REFERENCE);
   267→  }
   268→  if (!cachedNoiseRefEmbedding) {
   269→    cachedNoiseRefEmbedding = await embed(NOISE_REFERENCE);
   270→  }
   271→
   272→  // Find ALL_CAPS candidates with ≥2 words where every significant word has ≥4 alpha letters.
   273→  // Insignificant tokens (≤1 alpha letter: "/", "&", "+", ":", "D)", etc.) are filtered before
   274→  // the check so that multi-line joins with continuation punctuation still qualify.
   275→  const isStructuralHeading = (c: { text: string }): boolean => {
