   286→    const headerSim = cosineSimilarity(embedding, cachedHeaderRefEmbedding);
   287→    const noiseSim = cosineSimilarity(embedding, cachedNoiseRefEmbedding);
   288→    const rawScore = titleSim - Math.max(headerSim, noiseSim);
   289→    rawScored.push({ text: candidate.text, position: candidate.position, origin: candidate.origin, rawScore, embedding });
   290→  }
   291→
   292→  // Select baseHeading by embedding quality (rawScore), not position.
   293→  // This prevents OCR-garbled fragments from claiming the structural heading slot.
   294→  const structuralCandidates = rawScored.filter((s) => isStructuralHeading(s));
