   334→  const scored: Array<{ text: string; position: number; origin: CandidateOrigin; score: number; rawScore: number; baseScore: number; thresholdScore: number }> = rawScored.map((rs) => {
   335→    // Position factor: multiplicative tiebreaker — amplifies existing signal, doesn't replace it
   336→    const relativePosition = rs.position / lines.length;
   337→    const positionFactor = relativePosition < 0.5
   338→      ? 1.0 + 0.12 * (1 - relativePosition * 2)
   339→      : 1.0;
   340→
   341→    // ALL_CAPS bonus: recipe books use ALL_CAPS for titles and section headings
   342→    const allCapsBonus = isAllCaps(rs.text) && rs.text.replace(/[^a-zA-Z]/g, "").length >= 4
