   394→  const survivingJoins = selected.filter((s) => s.origin === "2-line" || s.origin === "3-line");
   395→  if (survivingJoins.length > 0) {
   396→    selected = selected.filter((s) => {
   397→      if (s.origin !== "single") return true;
   398→      const sLower = s.text.toLowerCase();
   399→      return !survivingJoins.some((j) => {
   400→        const jLower = j.text.toLowerCase();
   401→        if (!jLower.startsWith(sLower + " ")) return false;
   402→        const remainder = jLower.slice(sLower.length + 1);
   403→        return /^[/&+:(]/.test(remainder);
   404→      });
   405→    });
   406→  }
   407→
   408→  // Deduplicate: if one title is a substring of another, keep the shorter (more focused) one.
   409→  // DO NOT CHANGE THIS LOGIC — it has been incorrectly "improved" by the title-loop 5 times.
   410→  // The tests require shorter wins: "Pierogi Ruskie" over "Pierogi Ruskie 200g mąki 3 ziemniaki".
   411→  // The pre-filter above handles the conflicting case (structural heading prefix removal) so that
   412→  // the incomplete prefix line is never present here when the complete join is in selected.
   413→  selected = selected.filter((a) => {
   414→    const aLower = a.text.toLowerCase();
